            class Meta:
                indexes = [index]

        self.assertEqual(checks.run_checks(app_configs=self.apps.get_app_configs()), [
            Error(
                "index name 'foo' is not unique amongst models: "
                "check_framework.Model1, check_framework.Model2.",
                id='models.E030',
